import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Product } from '../types/index';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faChevronLeft, faStar as faSolidStar, faStarHalfAlt, faStar as faRegularStar } from '@fortawesome/free-solid-svg-icons';
import { mockReviews } from './Reviews';
import Home from './Home';
import { products } from '../data/products';

// 문의 폼 타입
interface InquiryForm {
  name: string;
  email: string;
  phone: string;
  category: string;
  subject: string;
  message: string;
}

const getProducts = () => {
  // Home 컴포넌트에서 popularProducts를 가져오는 대신, 실제로는 별도 데이터 파일로 분리하는 것이 좋음
  // 여기서는 Home에서 export한 popularProducts를 사용한다고 가정
  // @ts-ignore
  return Home?.prototype?.props?.popularProducts || [];
};

const ProductDetail: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  // 실제로는 product 데이터를 context나 별도 파일에서 import하는 것이 좋음
  // 여기서는 Home에서 popularProducts를 가져온다고 가정
  const product = products.find(p => p.id === Number(id));

  // 문의 폼 상태
  const [inquiryForm, setInquiryForm] = useState<InquiryForm>({
    name: '',
    email: '',
    phone: '',
    category: '상품 문의',
    subject: product ? `[상품문의] ${product.name}` : '',
    message: ''
  });

  const handleInquiryChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setInquiryForm(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleInquirySubmit = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    alert('문의가 성공적으로 접수되었습니다. 빠른 시일 내에 답변드리겠습니다.');
    setInquiryForm({
      name: '',
      email: '',
      phone: '',
      category: '상품 문의',
      subject: product ? `[상품문의] ${product.name}` : '',
      message: ''
    });
  };

  if (!product) {
    return <div className="text-center py-20">상품을 찾을 수 없습니다.</div>;
  }

  // 해당 상품에 대한 리뷰만 필터링
  const productReviews = mockReviews.filter((r: any) => r.product.includes(product.name));

  return (
    <div className="max-w-3xl mx-auto py-10 px-4">
      {/* 상단: 뒤로가기 */}
      <div className="mb-4">
        <Link to="/products" className="text-gray-500 hover:text-blue-600 flex items-center">
          <FontAwesomeIcon icon={faChevronLeft} className="mr-2" />
          상품 목록으로
        </Link>
      </div>

      {/* 상품 정보 */}
      <div className="bg-white rounded-lg shadow-md p-6 mb-8">
        <div className="flex flex-col md:flex-row items-center md:items-start gap-8">
          {/* 이미지/배경 */}
          <div
            className="w-48 h-48 rounded-lg bg-cover bg-center flex items-center justify-center"
            style={{
              backgroundImage: product.background ? `url(${product.background})` : undefined,
              backgroundColor: !product.background ? '#FFF7ED' : undefined
            }}
          >
            <FontAwesomeIcon
              icon={faSolidStar}
              className="text-6xl text-gray-300"
            />
          </div>
          {/* 텍스트 정보 */}
          <div className="flex-1">
            <h1 className="text-2xl font-bold mb-2">{product.name}</h1>
            <div className="text-gray-500 mb-2">{product.description}</div>
            <div className="flex items-end mb-2">
              {product.discountRate && (
                <span className="text-blue-600 font-bold text-lg mr-2">{product.discountRate}%</span>
              )}
              {product.originalPrice && (
                <span className="text-gray-400 line-through text-sm mr-2">{product.originalPrice.toLocaleString()}원</span>
              )}
              <span className="text-gray-900 font-bold text-2xl">{typeof product.price === 'number' ? product.price.toLocaleString() : product.price}원</span>
            </div>
            <button className="mt-4 w-full bg-blue-600 text-white py-3 rounded-md hover:bg-blue-700 transition duration-300 text-lg font-semibold">
              주문하기
            </button>
          </div>
        </div>
      </div>

      {/* 서비스 설명 */}
      <div className="bg-white rounded-lg shadow-md p-6 mb-8">
        <h2 className="text-xl font-bold mb-4">서비스 설명</h2>
        <div className="text-gray-700 leading-relaxed whitespace-pre-line">
          {product.description || '상품에 대한 상세 설명이 준비 중입니다.'}
        </div>
      </div>

      {/* 서비스 평가(리뷰) */}
      <div className="bg-white rounded-lg shadow-md p-6 mb-8">
        <h2 className="text-xl font-bold mb-4">서비스 평가</h2>
        {productReviews.length === 0 ? (
          <div className="text-gray-400">아직 후기가 없습니다.</div>
        ) : (
          <div className="space-y-6">
            {productReviews.slice(0, 5).map((review: any) => (
              <div key={review.id} className="border-b pb-4 mb-4 last:border-b-0 last:mb-0">
                <div className="flex items-center mb-2">
                  <span className="font-semibold text-blue-600 mr-2">{review.user}</span>
                  <span className="text-xs text-gray-400">{review.time}</span>
                  <span className="ml-3 flex items-center">
                    {Array.from({ length: 5 }).map((_, i) => (
                      <FontAwesomeIcon
                        key={i}
                        icon={i < review.rating ? faSolidStar : faRegularStar}
                        className={i < review.rating ? 'text-yellow-400' : 'text-gray-300'}
                      />
                    ))}
                  </span>
                </div>
                <div className="mb-2 text-gray-900">{review.content}</div>
                {review.reply && (
                  <div className="bg-gray-50 border-l-4 border-blue-400 p-3 text-sm text-gray-700 mt-2">
                    <div className="flex items-center mb-1">
                      <span className="font-bold text-blue-600">애드모어</span>
                      <span className="text-xs text-gray-400 ml-2">{review.replyTime}</span>
                    </div>
                    <span>{review.reply}</span>
                  </div>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* 1:1 문의 폼 */}
      <div className="bg-white rounded-lg shadow-md p-6 mb-8">
        <h2 className="text-xl font-bold mb-4">상품 문의</h2>
        <form onSubmit={handleInquirySubmit} className="space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">이름 *</label>
              <input
                type="text"
                name="name"
                value={inquiryForm.name}
                onChange={handleInquiryChange}
                required
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="이름을 입력해주세요"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">이메일 *</label>
              <input
                type="email"
                name="email"
                value={inquiryForm.email}
                onChange={handleInquiryChange}
                required
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="example@email.com"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">전화번호</label>
              <input
                type="tel"
                name="phone"
                value={inquiryForm.phone}
                onChange={handleInquiryChange}
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                placeholder="010-1234-5678"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">문의 유형 *</label>
              <select
                name="category"
                value={inquiryForm.category}
                onChange={handleInquiryChange}
                required
                className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                <option value="상품 문의">상품 문의</option>
                <option value="결제 문의">결제 문의</option>
                <option value="기술 지원">기술 지원</option>
                <option value="환불 문의">환불 문의</option>
                <option value="기타">기타</option>
              </select>
            </div>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">제목 *</label>
            <input
              type="text"
              name="subject"
              value={inquiryForm.subject}
              onChange={handleInquiryChange}
              required
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="문의 제목을 입력해주세요"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">문의 내용 *</label>
            <textarea
              name="message"
              value={inquiryForm.message}
              onChange={handleInquiryChange}
              required
              rows={6}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="문의 내용을 자세히 입력해주세요"
            />
          </div>
          <div className="flex justify-end">
            <button
              type="submit"
              className="bg-blue-600 text-white px-6 py-2 rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 transition duration-300"
            >
              문의하기
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ProductDetail;
